// Code added here will be run once
// whenever the node is deployed.
 const COLOUR = {
  RED : 0,
  GREEN : 1,
  BLUE : 2,
  WHITE : 3,
  ROSE : 4, 
  MAGENTA : 5,
  VIOLET : 6,
  AZURE : 7,
  CYAN : 8,
  AQUAMARINE : 9,
  CHARTREUSE :10,
  YELLOW : 11,
  ORANGE : 12
 };


 const MODE ={
  NONE : 0,
  SINE : 1,
  SQUARE : 2,
  TRIANGLE : 3,
  SAWTOOTH : 4,
  COLOUR_CHANGE :5,

};

const CHANNEL ={
  CHANNEL_NS : 0,
  CHANNEL_1 : 1,
  CHANNEL_2 : 2,
  CHANNEL_3 : 3

};

const CTRL_CMD_ID ={
  LED_CHANGE : 0
};

// Preserve any previously-set hue/saturation for this channel and
// only update the stored brightness (value), instead of blindly
// overwriting the whole colour state to hue:0/saturation:0/value:1
// every time this runs (that was resetting your percentage/colour
// back to white/100% on every Turn On or Turn Off).
var channelKey;
switch (msg.channel) {
  case "CHANNEL_1":
    channelKey = "channelOne";
    break;
  case "CHANNEL_2":
    channelKey = "channelTwo";
    break;
  case "CHANNEL_3":
    channelKey = "channelThree";
    break;
}

if (channelKey) {
    var existing = global.get(channelKey) || { hue: 0, saturation: 0, value: 1 };
    if (msg.brightness !== undefined) {
        existing.value = msg.brightness / 100;
    }
    global.set(channelKey, existing);
}


msg.baudrate = 115200;
var MSG_LEN = 10;
msg.payload = new Uint8Array(MSG_LEN);
msg.payload[0] = CTRL_CMD_ID.LED_CHANGE;
msg.payload[1] = CHANNEL[msg.channel];
msg.payload[2] = MODE[msg.mode];
msg.payload[3] = COLOUR[msg.colour];
msg.payload[4] = msg.brightness;
msg.payload[5] = (msg.period & 0xFF000000)>>24;
msg.payload[6] = (msg.period & 0x00FF0000)>>16;
msg.payload[7] = (msg.period & 0x0000FF00)>>8;
msg.payload[8] = (msg.period & 0x000000FF);
msg.payload[9] =0;

msg.payload = Buffer.from(msg.payload)
return msg;

msg.mode = "NONE";
if(msg.colour == undefined){
    msg.colour ="WHITE";
}
if(msg.brightness ==undefined){
    msg.brightness = 100;
}
msg.period =0;
return msg;

