var devices = [
    { id: "server_light", name: "Server Light" },
    { id: "top_shelf", name: "Top Shelf" },
    { id: "bottom_shelf", name: "Bottom Shelf" }
];

var msgs = devices.map(function (d) {
    var config = {
        name: d.name,
        unique_id: "led_" + d.id,
        schema: "json",
        command_topic: "home/light/" + d.id + "/set",
        state_topic: "home/light/" + d.id + "/state",
        brightness: true,
        supported_color_modes: ["hs"],
        qos: 0,
        device: {
            identifiers: ["led_strip_controller"],
            name: "LED Strip Controller",
            manufacturer: "DIY"
        }
    };
    return {
        topic: "homeassistant/light/" + d.id + "/config",
        payload: JSON.stringify(config),
        retain: true
    };
});

return [msgs];

var payload = msg.payload;
if (typeof payload !== "object" || payload === null) {
    node.warn("MQTT: payload was not a JSON object");
    return null;
}

var cmds = [];

if (payload.state !== undefined) {
    cmds.push({
        command: (payload.state === "ON") ? "TurnOnRequest" : "TurnOffRequest",
        channel: "CHANNEL_1"
    });
}

if (payload.color !== undefined) {
    cmds.push({
        command: "SetColorRequest",
        channel: "CHANNEL_1",
        payload: { hue: payload.color.h, saturation: payload.color.s / 100 }
    });
}

if (payload.brightness !== undefined) {
    cmds.push({
        command: "SetPercentageRequest",
        channel: "CHANNEL_1",
        payload: Math.round((payload.brightness / 255) * 100)
    });
}

return [cmds];

