const CHANNEL_MAP = {
    CHANNEL_1: { id: "server_light", key: "channelOne" },
    CHANNEL_2: { id: "top_shelf", key: "channelTwo" },
    CHANNEL_3: { id: "bottom_shelf", key: "channelThree" }
};

var info = CHANNEL_MAP[msg.channel];
if (!info) {
    // Not one of our HA-tracked channels (e.g. a raw test inject) -
    // just forward to serial, nothing to publish.
    return [msg, null];
}

var stats = global.get(info.key) || { hue: 0, saturation: 0, value: 0 };

var brightness255 = Math.max(0, Math.min(255, Math.round((stats.value || 0) * 255)));

var statePayload = {
    state: brightness255 > 0 ? "ON" : "OFF",
    brightness: brightness255,
    color: {
        h: stats.hue || 0,
        s: Math.max(0, Math.min(100, Math.round((stats.saturation || 0) * 100)))
    }
};

var stateMsg = {
    topic: "home/light/" + info.id + "/state",
    payload: JSON.stringify(statePayload),
    retain: true
};

return [msg, stateMsg];
